const body   = $input.first().json.body || $input.first().json;
const action = body.action || 'write';
const sd     = $getWorkflowStaticData('global');
if (!sd.buckets) sd.buckets = {};

// ── WRITE ─────────────────────────────────────────────────────────────────
if (action === 'write') {
  const h   = (body.hora || '00:00').substring(0, 2);
  const pk  = (body.project || 'VictorIA').replace(/[^a-zA-Z0-9]/g, '_');

  // source: 'window' = tiempo real de ventana activa (window-tracker)
  //         'claude' = acciones de Claude Code (hook)
  // Cada fuente tiene su propio bucket para no mezclar tiempos.
  const src = body.source ||
    (body.session === 'window-tracker' ? 'window' :
     (body.tool === 'WindowTracker'    ? 'window' : 'claude'));

  const key = `${body.dateKey}_${h}_${pk}_${src}`;

  if (!sd.buckets[key]) {
    sd.buckets[key] = {
      dateKey:    body.dateKey || '',
      hour:       h,
      hora:       body.hora    || `${h}:00`,
      project:    body.project || 'Victor IA',
      client:     body.client  || body.project || 'Victor IA',
      cat:        body.cat     || 'Desarrollo',
      source:     src,
      swDuration: {},   // { swId: segundos acumulados }
      contexts:   {},   // { swId: [archivos/secciones vistas] }
      files: [], langs: [], termCmds: [], gitOps: [],
      count: 0, saves: 0, edits: 0, terminals: 0, debugs: 0, creates: 0,
      sessions: []
    };
  }

  const b = sd.buckets[key];
  b.count++;

  // ── swDuration ────────────────────────────────────────────────────────
  const incoming = body.swDuration || {};
  for (const [sw, secs] of Object.entries(incoming)) {
    b.swDuration[sw] = (b.swDuration[sw] || 0) + (secs || 0);
  }
  // Para source=claude sin swDuration explícita, estima 60s (no aplica a window)
  if (src === 'claude' && !Object.keys(incoming).length) {
    (body.sw || []).forEach(sw => {
      b.swDuration[sw] = (b.swDuration[sw] || 0) + 60;
    });
  }

  // ── Contextos (archivos o secciones activas por app) ──────────────────
  const ctxIn = (body.meta && body.meta.contexts) || {};
  for (const [sw, ctxList] of Object.entries(ctxIn)) {
    if (!b.contexts[sw]) b.contexts[sw] = [];
    (ctxList || []).forEach(c => {
      if (c && !b.contexts[sw].includes(c)) b.contexts[sw].push(c);
    });
    if (b.contexts[sw].length > 10) b.contexts[sw] = b.contexts[sw].slice(-10);
  }

  // ── Archivos (hook claude) ─────────────────────────────────────────────
  (body.file ? body.file.split(', ') : []).map(f => f.trim()).filter(Boolean)
    .forEach(f => { if (!b.files.includes(f)) b.files.push(f); });

  // ── Meta ──────────────────────────────────────────────────────────────
  const meta = body.meta || {};
  if (meta.langs)    meta.langs.forEach(l    => { if (!b.langs.includes(l))     b.langs.push(l);     });
  if (meta.termCmds) meta.termCmds.forEach(c => { if (!b.termCmds.includes(c)) b.termCmds.push(c); });
  if (meta.gitOps)   meta.gitOps.forEach(g   => { if (!b.gitOps.includes(g))   b.gitOps.push(g);   });
  b.saves     += meta.saves     || 0;
  b.edits     += meta.edits     || 0;
  b.terminals += meta.terminals || 0;
  b.debugs    += meta.debugs    || 0;
  b.creates   += meta.creates   || 0;

  if (body.session && !b.sessions.includes(body.session)) b.sessions.push(body.session);

  if (b.files.length    > 40) b.files    = b.files.slice(-40);
  if (b.termCmds.length > 25) b.termCmds = b.termCmds.slice(-25);
  if (b.gitOps.length   > 15) b.gitOps   = b.gitOps.slice(-15);

  return [{ json: { ok: true, key, count: b.count, source: src } }];

// ── READ ──────────────────────────────────────────────────────────────────
} else {
  const buckets = Object.values(sd.buckets || {});
  buckets.sort((a, b) => (`${b.dateKey}_${b.hour}`).localeCompare(`${a.dateKey}_${a.hour}`));

  const entries = buckets.map(b => {
    const src = b.source || 'window';

    const swEntries = Object.entries(b.swDuration || {})
      .filter(([, s]) => s > 0)
      .sort((a, bb) => bb[1] - a[1]);
    const swList = swEntries.map(([sw]) => sw);
    if (!swList.length) swList.push(src === 'window' ? 'vscode' : 'claude-code');

    // Duración: window = tiempo real sin cap | claude = estimado con mín 15min
    const totalSW = swEntries.reduce((acc, [, s]) => acc + s, 0);
    const durSec  = src === 'window'
      ? Math.max(totalSW, 0)
      : Math.min(Math.max(totalSW, 900), 3600);
    const dur = Math.round((durSec / 3600) * 4) / 4;

    // Desglose: 'after-effects 12min [banner.aep] · hubspot 8min'
    const swBreakdown = swEntries.slice(0, 6).map(([sw, s]) => {
      const mins = Math.round(s / 60);
      const ctx  = (b.contexts && b.contexts[sw] || []).slice(0, 2).join(', ');
      return ctx ? `${sw} ${mins}min [${ctx}]` : `${sw} ${mins}min`;
    }).join(' · ');

    // Descripción según fuente
    let desc;
    if (src === 'window') {
      const appParts = swEntries.slice(0, 3).map(([sw, s]) => {
        const mins = Math.round(s / 60);
        const ctx  = (b.contexts && b.contexts[sw] || [])[0] || '';
        return ctx ? `${sw}:${ctx} ${mins}min` : `${sw} ${mins}min`;
      });
      desc = `\u{1F4CA} Apps: ${appParts.join(' \u00B7 ') || b.project}`;
    } else {
      const topFiles = b.files.slice(0, 3).join(', ') + (b.files.length > 3 ? ` +${b.files.length - 3}` : '');
      const actParts = [];
      if (b.saves  > 0) actParts.push(`${b.saves} saves`);
      if (b.edits  > 0) actParts.push(`${b.edits} edits`);
      if (b.debugs > 0) actParts.push(`${b.debugs} debug`);
      if (b.gitOps && b.gitOps.length) actParts.push(b.gitOps.slice(0, 2).join(', '));
      const actStr = actParts.length ? ` \u2014 ${actParts.join(' \u00B7 ')}` : '';
      desc = `\u{1F916} Claude: ${topFiles || b.project}${actStr}`;
    }

    const obs = src === 'window'
      ? `Window tracking \u00B7 ${swBreakdown || swList.join(', ')}`
      : `Claude Code \u00B7 ${b.sessions.length} sesi\u00F3n(es) \u00B7 ${swBreakdown || swList.join(', ')}`;

    const noteParts = [];
    if (b.langs    && b.langs.length)    noteParts.push(`Langs: ${b.langs.join(', ')}`);
    if (b.termCmds && b.termCmds.length) noteParts.push(`Cmds: ${b.termCmds.slice(0, 4).join(' | ')}`);
    if (swBreakdown) noteParts.push(`SW: ${swBreakdown}`);
    const notes = noteParts.join(' | ') || `Apps: ${swList.slice(0, 5).join(', ')}`;

    const pk = b.project.replace(/[^a-zA-Z0-9]/g, '_');
    return {
      id:         `auto_${b.dateKey}_${b.hour}_${pk}_${src}`,
      dateKey:    b.dateKey,
      hora:       `${String(b.hour).padStart(2, '0')}:00`,
      source:     src,
      desc,
      cat:        b.cat,
      project:    b.project,
      client:     b.client || b.project,
      status:     'Completado',
      priority:   'Media',
      dur,
      durSec,
      tags:       [],
      rework:     0,
      obs,
      notes,
      sw:         swList,
      swDuration: b.swDuration,
      contexts:   b.contexts || {},
      isAuto:     true
    };
  });

  return [{ json: { entries } }];
}
